content.content:
1	package tailer
2	
3	import (
4		"bufio"
5		"encoding/json"
6		"fmt"
7		"io"
8		"os"
9		"path/filepath"
10		"strings"
11		"time"
12	
13		"irrlicht/core/pkg/capacity"
14	)
15	
16	// MessageEvent represents a single message event from transcript
17	type MessageEvent struct {
18		Timestamp time.Time `json:"timestamp"`
19		EventType string    `json:"event_type"`
20		Content   string    `json:"content,omitempty"`
21	}
22	
23	// SessionMetrics holds computed performance metrics
24	type SessionMetrics struct {
25		MessagesPerMinute   float64        `json:"messages_per_minute"`
26		ElapsedSeconds      int64          `json:"elapsed_seconds"`
27		LastMessageAt       time.Time      `json:"last_message_at"`
28		MessageHistory      []MessageEvent `json:"-"` // Sliding window, not serialized
29		SessionStartAt      time.Time      `json:"session_start_at"`
30		TotalTokens         int64          `json:"total_tokens,omitempty"`
31		InputTokens         int64          `json:"input_tokens,omitempty"`
32		OutputTokens        int64          `json:"output_tokens,omitempty"`
33		CacheReadTokens     int64          `json:"cache_read_tokens,omitempty"`
34		CacheCreationTokens int64          `json:"cache_creation_tokens,omitempty"`
35		EstimatedCostUSD    float64        `json:"estimated_cost_usd,omitempty"`
36		ModelName           string         `json:"model_name,omitempty"`
37		ContextWindow       int64          `json:"context_window,omitempty"`
38		ContextUtilization  float64        `json:"context_utilization_percentage,omitempty"`
39		PressureLevel       string         `json:"pressure_level,omitempty"` // "safe", "caution", "warning", "critical"
40	
41		// Raw event data for real-time client-side calculations
42		TotalEventCount        int64     `json:"total_event_count,omitempty"`
43		RecentEventCount       int64     `json:"recent_event_count,omitempty"`
44		RecentEventWindowStart time.Time `json:"recent_event_window_start,omitempty"`
45	
46		// Tool call tracking — count unmatched tool_use/tool_result pairs
47		HasOpenToolCall   bool `json:"has_open_tool_call"`
48		OpenToolCallCount int  `json:"open_tool_call_count,omitempty"`
49	
50		// LastEventType is the event type of the most recent message event in
51		// the transcript (e.g. "assistant", "user", "tool_use", "tool_result").
52		// Used for content-based working/waiting detection.
53		LastEventType string `json:"last_event_type,omitempty"`
54	
55		// LastOpenToolNames holds the tool names from the most recent assistant
56		// message that called tools. Cleared when a user message appears.
57		// Used to detect user-blocking tools (AskUserQuestion, ExitPlanMode).
58		LastOpenToolNames []string `json:"last_open_tool_names,omitempty"`
59	
60		// LastToolResultWasError is true when the most recently processed
61		// tool_result content block had is_error=true (user rejection / ESC).
62		LastToolResultWasError bool `json:"last_tool_result_was_error"`
63	
64		// LastCWD is the most recent working directory seen in the transcript.
65		// Extracted during parsing so callers don't need a separate file read.
66		LastCWD string `json:"last_cwd,omitempty"`
67	
68		// LastAssistantText is the text content of the most recent assistant
69		// message, truncated to ~200 characters.
70		LastAssistantText string `json:"last_assistant_text,omitempty"`
71	
72		// PermissionMode is the session's permission mode (e.g. "default",
73		// "plan", "bypassPermissions"). Extracted from "permission-mode" events.
74		PermissionMode string `json:"permission_mode,omitempty"`
75	}
76	
77	// TranscriptTailer monitors transcript files and computes metrics.
78	// Format-specific parsing is delegated to a TranscriptParser.
79	type TranscriptTailer struct {
80		path        string
81		lastOffset  int64
82		metrics     *SessionMetrics
83		windowSize  time.Duration // Default 60 seconds
84		capacityMgr *capacity.CapacityManager
85	
86		// parser handles format-specific line parsing (Claude Code, Codex, Pi).
87		parser TranscriptParser
88	
89		// adapter name for model config fallback.
90		adapter string
91	
92		// Context window override from transcript or extended context model suffix.
93		contextWindowOverride int64
94	
95		// Tool call pairing counters — accumulated from ParsedEvent deltas.
96		toolUseCount    int
97		toolResultCount int
98	
99		// lastOpenToolNames holds tool names from open tool calls.
100		lastOpenToolNames []string
101	
102		// contentChars accumulates character count from message content for
103		// token estimation when explicit token counts aren't available.
104		contentChars int64
105	
106		// Token breakdown accumulators (latest snapshot, not cumulative).
107		inputTokens         int64
108		outputTokens        int64
109		cacheReadTokens     int64
110		cacheCreationTokens int64
111	
112		// lastToolResultWasError tracks is_error on the most recent tool_result.
113		lastToolResultWasError bool
114	
115		// lastCWD tracks the most recent working directory seen in transcript lines.
116		lastCWD string
117	
118		// lastAssistantText holds the text content of the most recent assistant
119		// message, truncated to ~200 characters.
120		lastAssistantText string
121	}
122	
123	// NewTranscriptTailer creates a new tailer for the given transcript path.
124	// The parser handles format-specific line parsing; adapter is used for model
125	// config fallback.
126	func NewTranscriptTailer(path string, parser TranscriptParser, adapter string) *TranscriptTailer {
127		return &TranscriptTailer{
128			path:        path,
129			lastOffset:  0,
130			capacityMgr: capacity.DefaultCapacityManager(),
131			parser:      parser,
132			adapter:     adapter,
133			metrics: &SessionMetrics{
134				MessageHistory: make([]MessageEvent, 0),
135				SessionStartAt: time.Time{},
136			},
137			windowSize: 60 * time.Second,
138		}
139	}
140	
141	// SetSessionStartTime allows preserving the session start time across multiple invocations
142	func (t *TranscriptTailer) SetSessionStartTime(startTime time.Time) {
143		if t.metrics != nil {
144			t.metrics.SessionStartAt = startTime
145		}
146	}
147	
148	// TailAndProcess reads the last ~64KB of transcript and processes new entries
149	func (t *TranscriptTailer) TailAndProcess() (*SessionMetrics, error) {
150		file, err := os.Open(t.path)
151		if err != nil {
152			return nil, fmt.Errorf("failed to open transcript: %w", err)
153		}
154		defer file.Close()
155	
156		stat, err := file.Stat()
157		if err != nil {
158			return nil, fmt.Errorf("failed to stat transcript: %w", err)
159		}
160		fileSize := stat.Size()
161	
162		const maxTailSize = 64 * 1024
163		startPos := int64(0)
164		switch {
165		case fileSize < t.lastOffset:
166			// File rotated/truncated.
167			startPos = 0
168		case t.lastOffset > 0:
169			// Normal incremental path: never skip ahead of the last processed byte.
170			startPos = t.lastOffset
171		case fileSize > maxTailSize:
172			// Initial read for large files: only tail the latest window.
173			startPos = fileSize - maxTailSize
174		}
175	
176		_, err = file.Seek(startPos, io.SeekStart)
177		if err != nil {
178			return nil, fmt.Errorf("failed to seek transcript: %w", err)
179		}
180	
181		currentOffset := startPos
182		var reader io.Reader = file
183	
184		// On the initial truncated read of a large file, we may start in the
185		// middle of a JSON line. If so, discard the partial line to align scanner
186		// to a full JSONL entry boundary.
187		if t.lastOffset == 0 && startPos > 0 {
188			prev := []byte{0}
189			if _, err := file.ReadAt(prev, startPos-1); err == nil && prev[0] != '\n' {
190				br := bufio.NewReader(file)
191				if discarded, err := br.ReadString('\n'); err == nil {
192					currentOffset += int64(len(discarded))
193				} else {
194					return nil, fmt.Errorf("failed to align transcript boundary: %w", err)
195				}
196				reader = br
197			}
198		}
199	
200		scanner := bufio.NewScanner(reader)
201		// Large tool results (especially from Pi/Codex read/bash output) can exceed
202		// bufio.Scanner's 64KB default token size.
203		scanner.Buffer(make([]byte, 64*1024), 2*1024*1024)
204	
205		for scanner.Scan() {
206			line := strings.TrimSpace(scanner.Text())
207			currentOffset += int64(len(scanner.Bytes()) + 1)
208	
209			if line == "" {
210				continue
211			}
212	
213			// Quick JSON check.
214			if !strings.HasPrefix(line, "{") || !strings.HasSuffix(line, "}") {
215				continue
216			}
217	
218			var raw map[string]interface{}
219			if err := json.Unmarshal([]byte(line), &raw); err != nil {
220				continue
221			}
222	
223			// Delegate to format-specific parser.
224			parsed := t.parser.ParseLine(raw)
225			if parsed == nil || parsed.Skip {
226				// Even for skipped events, apply metadata that the parser extracted
227				// (e.g. model from model_change, CWD from session header).
228				if parsed != nil {
229					t.applyMetadata(parsed)
230				}
231				continue
232			}
233	
234			// Apply tool tracking deltas from the parser.
235			t.toolUseCount += len(parsed.ToolUseNames)
236			t.lastOpenToolNames = append(t.lastOpenToolNames, parsed.ToolUseNames...)
237			t.toolResultCount += parsed.ToolResultCount
238			for i := 0; i < parsed.ToolResultCount; i++ {
239				if len(t.lastOpenToolNames) > 0 {
240					t.lastOpenToolNames = t.lastOpenToolNames[1:]
241				}
242			}
243			if parsed.ClearToolNames && parsed.ToolResultCount == 0 {
244				t.lastOpenToolNames = nil
245			}
246			if parsed.IsError {
247				t.lastToolResultWasError = true
248			} else if parsed.ToolResultCount > 0 {
249				t.lastToolResultWasError = false
250			}
251	
252			// Apply metadata.
253			t.applyMetadata(parsed)
254	
255			// Track assistant text.
256			if parsed.AssistantText != "" {
257				t.lastAssistantText = parsed.AssistantText
258			}
259			if parsed.ClearToolNames {
260				t.lastAssistantText = ""
261			}
262	
263			// Accumulate content chars.
264			t.contentChars += parsed.ContentChars
265	
266			t.addMessageEvent(MessageEvent{
267				Timestamp: parsed.Timestamp,
268				EventType: parsed.EventType,
269			})
270		}
271	
272		t.lastOffset = currentOffset
273	
274		// Compute current metrics.
275		t.computeMetrics()
276	
277		// Model config fallback.
278		if t.metrics.ModelName == "" {
279			if defaultModel := getDefaultModelFromConfig(t.adapter); defaultModel != "" {
280				t.metrics.ModelName = defaultModel
281			}
282		}
283	
284		// Estimate tokens from content chars when no explicit token data exists.
285		if t.metrics.TotalTokens == 0 && t.contentChars > 0 && t.capacityMgr != nil && t.metrics.ModelName != "" {
286			cap := t.capacityMgr.GetModelCapacity(t.metrics.ModelName)
287			ratio := cap.CharToTokenRatio
288			if ratio <= 0 {
289				ratio = 4.0
290			}
291			t.metrics.TotalTokens = int64(float64(t.contentChars) / ratio)
292			if t.inputTokens == 0 && t.outputTokens == 0 {
293				t.inputTokens = t.metrics.TotalTokens * 9 / 10
294				t.outputTokens = t.metrics.TotalTokens - t.inputTokens
295			}
296		}
297	
298		// Recompute cost if token estimation filled in the breakdown.
299		if t.metrics.EstimatedCostUSD == 0 && t.inputTokens > 0 && t.capacityMgr != nil && t.metrics.ModelName != "" {
300			t.metrics.InputTokens = t.inputTokens
301			t.metrics.OutputTokens = t.outputTokens
302			t.metrics.EstimatedCostUSD = t.capacityMgr.EstimateCostUSD(
303				t.metrics.ModelName, t.inputTokens, t.outputTokens, t.cacheReadTokens, t.cacheCreationTokens)
304		}
305	
306		t.computeContextUtilization()
307	
308		return t.metrics, scanner.Err()
309	}
310	
311	// applyMetadata applies model/token/CWD/permission metadata from a parsed event.
312	func (t *TranscriptTailer) applyMetadata(parsed *ParsedEvent) {
313		if parsed.ModelName != "" {
314			if strings.Contains(parsed.ModelName, "[1m]") {
315				t.contextWindowOverride = 1000000
316			}
317			t.metrics.ModelName = NormalizeModelName(parsed.ModelName)
318		}
319		if parsed.ContextWindow > 0 {
320			t.contextWindowOverride = parsed.ContextWindow
321		}
322		if parsed.Tokens != nil {
323			if parsed.Tokens.Total > 0 {
324				t.metrics.TotalTokens = parsed.Tokens.Total
325			}
326			if parsed.Tokens.Input > 0 || parsed.Tokens.Output > 0 {
327				t.inputTokens = parsed.Tokens.Input
328				t.outputTokens = parsed.Tokens.Output
329				t.cacheReadTokens = parsed.Tokens.CacheRead
330				t.cacheCreationTokens = parsed.Tokens.CacheCreation
331			}
332		}
333		if parsed.CWD != "" {
334			t.lastCWD = parsed.CWD
335		}
336		if parsed.PermissionMode != "" {
337			t.metrics.PermissionMode = parsed.PermissionMode
338		}
339	}
340	
341	// addMessageEvent adds a new message event and maintains sliding window.
342	// Tool call counting is NOT done here — it's handled from ParsedEvent deltas
343	// in TailAndProcess to avoid double-counting.
344	func (t *TranscriptTailer) addMessageEvent(event MessageEvent) {
345		t.metrics.MessageHistory = append(t.metrics.MessageHistory, event)
346		t.metrics.LastMessageAt = event.Timestamp
347		t.metrics.LastEventType = event.EventType
348	
349		if t.metrics.SessionStartAt.IsZero() || event.Timestamp.Before(t.metrics.SessionStartAt) {
350			t.metrics.SessionStartAt = event.Timestamp
351		}
352	}
353	
354	// computeMetrics calculates messages per minute and elapsed time
355	func (t *TranscriptTailer) computeMetrics() {
356		if len(t.metrics.MessageHistory) == 0 {
357			t.metrics.MessagesPerMinute = 0
358			t.metrics.ElapsedSeconds = 0
359			t.metrics.TotalEventCount = 0
360			t.metrics.RecentEventCount = 0
361			t.metrics.RecentEventWindowStart = time.Time{}
362			return
363		}
364	
365		currentTime := time.Now()
366		latestTime := t.metrics.LastMessageAt
367		if latestTime.IsZero() {
368			latestTime = currentTime
369		}
370	
371		if !t.metrics.SessionStartAt.IsZero() {
372			t.metrics.ElapsedSeconds = int64(latestTime.Sub(t.metrics.SessionStartAt).Seconds())
373		}
374	
375		t.metrics.TotalEventCount = int64(len(t.metrics.MessageHistory))
376	
377		fiveMinutesAgo := currentTime.Add(-5 * time.Minute)
378		windowStart := fiveMinutesAgo
379		if t.metrics.SessionStartAt.After(fiveMinutesAgo) {
380			windowStart = t.metrics.SessionStartAt
381		}
382		t.metrics.RecentEventWindowStart = windowStart
383	
384		recentEventCount := int64(0)
385		for _, msg := range t.metrics.MessageHistory {
386			if msg.Timestamp.After(windowStart) || msg.Timestamp.Equal(windowStart) {
387				recentEventCount++
388			}
389		}
390		t.metrics.RecentEventCount = recentEventCount
391	
392		// Compute open tool call count from pairing counters.
393		openCalls := t.toolUseCount - t.toolResultCount
394		if openCalls < 0 {
395			openCalls = 0
396		}
397		t.metrics.OpenToolCallCount = openCalls
398		t.metrics.HasOpenToolCall = openCalls > 0
399		t.metrics.LastOpenToolNames = t.lastOpenToolNames
400		t.metrics.LastToolResultWasError = t.lastToolResultWasError
401		t.metrics.LastCWD = t.lastCWD
402		t.metrics.LastAssistantText = t.lastAssistantText
403	
404		// Token breakdown + estimated cost.
405		t.metrics.InputTokens = t.inputTokens
406		t.metrics.OutputTokens = t.outputTokens
407		t.metrics.CacheReadTokens = t.cacheReadTokens
408		t.metrics.CacheCreationTokens = t.cacheCreationTokens
409		if t.capacityMgr != nil && t.metrics.ModelName != "" {
410			t.metrics.EstimatedCostUSD = t.capacityMgr.EstimateCostUSD(
411				t.metrics.ModelName, t.inputTokens, t.outputTokens, t.cacheReadTokens, t.cacheCreationTokens)
412		}
413	
414		// Sliding window for messages per minute.
415		legacyWindowStart := latestTime.Add(-t.windowSize)
416		messageCount := 0
417		filteredHistory := make([]MessageEvent, 0, len(t.metrics.MessageHistory))
418		for _, msg := range t.metrics.MessageHistory {
419			if msg.Timestamp.After(legacyWindowStart) || msg.Timestamp.Equal(legacyWindowStart) {
420				filteredHistory = append(filteredHistory, msg)
421				messageCount++
422			}
423		}
424		t.metrics.MessageHistory = filteredHistory
425	
426		if messageCount > 0 {
427			if len(filteredHistory) > 1 {
428				timeSpan := latestTime.Sub(filteredHistory[0].Timestamp)
429				if timeSpan > 0 {
430					t.metrics.MessagesPerMinute = float64(messageCount) / timeSpan.Minutes()
431				} else {
432					t.metrics.MessagesPerMinute = float64(messageCount)
433				}
434			} else {
435				t.metrics.MessagesPerMinute = float64(messageCount) / t.windowSize.Minutes()
436			}
437		} else {
438			t.metrics.MessagesPerMinute = 0
439		}
440	}
441	
442	// GetMetrics returns current computed metrics
443	func (t *TranscriptTailer) GetMetrics() *SessionMetrics {
444		if t.metrics == nil {
445			return &SessionMetrics{}
446		}
447		return t.metrics
448	}
449	
450	// ResetOffset resets the file offset (useful for testing or file rotation)
451	func (t *TranscriptTailer) ResetOffset() {
452		t.lastOffset = 0
453	}
454	
455	// computeContextUtilization calculates context utilization percentage and pressure level.
456	func (t *TranscriptTailer) computeContextUtilization() {
457		if t.metrics.TotalTokens == 0 || t.metrics.ModelName == "" {
458			t.metrics.ContextUtilization = 0.0
459			t.metrics.PressureLevel = "unknown"
460			return
461		}
462	
463		var effectiveContextWindow int64
464	
465		if t.contextWindowOverride > 0 {
466			effectiveContextWindow = t.contextWindowOverride
467		}
468	
469		if effectiveContextWindow <= 0 && t.capacityMgr != nil {
470			cap := t.capacityMgr.GetModelCapacity(t.metrics.ModelName)
471			if ctx1m, ok := cap.BetaFeatures["context_1m"]; ok && ctx1m > 0 {
472				effectiveContextWindow = ctx1m
473			} else if cap.ContextWindow > 0 {
474				effectiveContextWindow = cap.ContextWindow
475			}
476		}
477	
478		// Unknown model: no context window data available — report raw tokens only.
479		if effectiveContextWindow <= 0 {
480			t.metrics.ContextWindow = 0
481			t.metrics.ContextUtilization = 0
482			t.metrics.PressureLevel = "unknown"
483			return
484		}
485	
486		utilizationPercentage := (float64(t.metrics.TotalTokens) / float64(effectiveContextWindow)) * 100
487	
488		pressureLevel := "safe"
489		if utilizationPercentage >= 90 {
490			pressureLevel = "critical"
491		} else if utilizationPercentage >= 80 {
492			pressureLevel = "warning"
493		} else if utilizationPercentage >= 60 {
494			pressureLevel = "caution"
495		}
496	
497		t.metrics.ContextWindow = effectiveContextWindow
498		t.metrics.ContextUtilization = utilizationPercentage
499		t.metrics.PressureLevel = pressureLevel
500	}
501	
502	// --- Model config fallback ---
503	
504	// getDefaultModelFromConfig reads the default model from the appropriate config
505	// based on adapter name.
506	func getDefaultModelFromConfig(adapter string) string {
507		homeDir, err := os.UserHomeDir()
508		if err != nil {
509			return ""
510		}
511		switch adapter {
512		case "pi":
513			return getPiModel(homeDir)
514		case "codex":
515			return getCodexModel(homeDir)
516		default:
517			return getClaudeModel(homeDir)
518		}
519	}
520	
521	func getClaudeModel(homeDir string) string {
522		data, err := os.ReadFile(filepath.Join(homeDir, ".claude", "settings.json"))
523		if err != nil {
524			return ""
525		}
526		var settings map[string]interface{}
527		if err := json.Unmarshal(data, &settings); err != nil {
528			return ""
529		}
530		if model, ok := settings["model"].(string); ok {
531			return NormalizeModelName(model)
532		}
533		return ""
534	}
535	
536	func getCodexModel(homeDir string) string {
537		data, err := os.ReadFile(filepath.Join(homeDir, ".codex", "config.toml"))
538		if err != nil {
539			return ""
540		}
541		for _, line := range strings.Split(string(data), "\n") {
542			line = strings.TrimSpace(line)
543			if strings.HasPrefix(line, "model") && strings.Contains(line, "=") {
544				parts := strings.SplitN(line, "=", 2)
545				if strings.TrimSpace(parts[0]) == "model" {
546					model := strings.Trim(strings.TrimSpace(parts[1]), "\"'")
547					if model != "" {
548						return model
549					}
550				}
551			}
552		}
553		return ""
554	}
555	
556	func getPiModel(homeDir string) string {
557		data, err := os.ReadFile(filepath.Join(homeDir, ".pi", "agent", "settings.json"))
558		if err != nil {
559			return ""
560		}
561		var settings map[string]interface{}
562		if err := json.Unmarshal(data, &settings); err != nil {
563			return ""
564		}
565		if model, ok := settings["defaultModel"].(string); ok {
566			return NormalizeModelName(model)
567		}
568		return ""
569	}
570	
