1	// Package tailer provides transcript tailing and metrics computation.
2	// Format-specific parsing is delegated to TranscriptParser implementations
3	// that live in each agent adapter package.
4	package tailer
5	
6	import (
7		"regexp"
8		"strings"
9		"time"
10	)
11	
12	// ParsedEvent is the normalized output from a format-specific transcript parser.
13	// Each parser maps its native event structure into these fields.
14	type ParsedEvent struct {
15		EventType string    // normalized: "assistant_message", "user_message", "turn_done", etc.
16		Timestamp time.Time // event timestamp
17		Skip      bool      // true → ignore this line entirely
18	
19		// Tool tracking — parser reports deltas, tailer accumulates.
20		ToolUseNames    []string // tool names from tool_use/toolCall blocks in this event
21		ToolResultCount int      // number of tool_result blocks in this event
22		IsError         bool     // true if the tool result had is_error=true
23		ClearToolNames  bool     // true → reset lastOpenToolNames (on user messages)
24	
25		// Metadata extracted by the parser.
26		ModelName      string
27		ContextWindow  int64
28		Tokens         *TokenSnapshot // nil = no token data in this event
29		AssistantText  string         // ≤200 chars, for waiting-state display
30		ContentChars   int64          // character count for token estimation
31		CWD            string         // working directory if found
32		PermissionMode string         // Claude Code only
33	}
34	
35	// TokenSnapshot holds a token breakdown from a single event.
36	type TokenSnapshot struct {
37		Input         int64
38		Output        int64
39		CacheRead     int64
40		CacheCreation int64
41		Total         int64
42	}
43	
44	// TranscriptParser parses a single JSONL line from a specific transcript format
45	// and returns a normalized ParsedEvent. Implementations live in each agent
46	// adapter package (claudecode, codex, pi).
47	type TranscriptParser interface {
48		// ParseLine parses a raw JSON map and returns a normalized event.
49		// Returns nil for lines that should be silently ignored (no event emitted).
50		ParseLine(raw map[string]interface{}) *ParsedEvent
51	}
52	
53	// --- Shared helpers used by multiple parsers ---
54	
55	// NormalizeModelName normalizes model names by removing date suffixes, extended
56	// context markers, and handling aliases. Exported for use by adapter parsers.
57	func NormalizeModelName(rawModel string) string {
58		if rawModel == "" {
59			return ""
60		}
61	
62		// Strip extended context suffix (e.g. "claude-opus-4-6[1m]")
63		rawModel = strings.TrimSuffix(rawModel, "[1m]")
64	
65		// Handle common aliases first
66		aliases := map[string]string{
67			"opusplan": "claude-opus-4-1",
68			"sonnet":   "claude-sonnet-4-6",
69			"haiku":    "claude-haiku-4-5",
70		}
71		if normalized, exists := aliases[rawModel]; exists {
72			return normalized
73		}
74	
75		// Remove date suffixes (e.g., "claude-opus-4-6-20250715" -> "claude-opus-4-6")
76		datePattern := regexp.MustCompile(`-\d{8}$`)
77		normalized := datePattern.ReplaceAllString(rawModel, "")
78	
79		// Match most-specific patterns first (longer model IDs before shorter)
80		switch {
81		case strings.Contains(normalized, "claude-opus-4-6"):
82			return "claude-opus-4-6"
83		case strings.Contains(normalized, "claude-sonnet-4-6"):
84			return "claude-sonnet-4-6"
85		case strings.Contains(normalized, "claude-sonnet-4-5"):
86			return "claude-sonnet-4-5"
87		case strings.Contains(normalized, "claude-haiku-4-5"):
88			return "claude-haiku-4-5"
89		case strings.Contains(normalized, "claude-opus-4-1"):
90			return "claude-opus-4-1"
91		case strings.Contains(normalized, "claude-sonnet-4"):
92			return "claude-4-sonnet"
93		case strings.Contains(normalized, "claude-3.5-sonnet"):
94			return "claude-3.5-sonnet"
95		case strings.Contains(normalized, "claude-3.5-haiku"):
96			return "claude-3.5-haiku"
97		}
98		return normalized
99	}
100	
101	// ExtractAssistantText extracts and concatenates text blocks from an assistant
102	// message, returning at most 200 characters. Checks both Claude Code
103	// (message.content[].text) and Codex (content[].text / content[].output_text) formats.
104	func ExtractAssistantText(raw map[string]interface{}) string {
105		var parts []string
106	
107		collectText := func(arr []interface{}) {
108			for _, item := range arr {
109				if block, ok := item.(map[string]interface{}); ok {
110					bt := block["type"]
111					if bt == "text" || bt == "output_text" {
112						if text, ok := block["text"].(string); ok && text != "" {
113							parts = append(parts, text)
114						}
115					}
116				}
117			}
118		}
119	
120		// Claude Code: message.content[]
121		if msg, ok := raw["message"].(map[string]interface{}); ok {
122			if arr, ok := msg["content"].([]interface{}); ok {
123				collectText(arr)
124			}
125		}
126		// Codex: top-level content[]
127		if arr, ok := raw["content"].([]interface{}); ok {
128			collectText(arr)
129		}
130	
131		var text string
132		switch len(parts) {
133		case 0:
134			return ""
135		case 1:
136			text = strings.TrimSpace(parts[0])
137		default:
138			text = strings.TrimSpace(strings.Join(parts, " "))
139		}
140	
